export const getClimate = state => CLIMATE_DB[state] || null;

export function calcFromSpec(spec, price) {
  if (!spec) return 0;
  if (spec.t === "pct") return Math.round(price * spec.r);
  if (spec.t === "fixed") return spec.v;
  return 0;
}

